class Solution {
    public long findMaximumNumber(long k, int x) {
        int power = (int) Math.pow(2, x);
        long result = 1L;
        for (int i = 0; i < power; i++) {
            result *= (1L << i);
        }
        return result / (1L << (power - k));
    }
}
```

